def split_role(job_role):
    for prefix in PREFIX_MAP:
        token = prefix + ' '
        if job_role.startswith(token):
            return prefix, job_role[len(token):]
    return None, job_role

def get_experience(prefix, role_info):
    if prefix in PREFIX_MAP:
        return PREFIX_MAP[prefix]
    return role_info['default_experience']

def main():
    # Generate all roles from ROLE_DATA
    rows = []
    for base_role, info in ROLE_DATA.items():
        # Add base role
        rows.append({
            'job_role': base_role,
            'skills': info['skills'],
            'domain': info['domain'],
            'required_skills': info['required_skills'],
            'demand_level_india': info['demand'],
            'experience_alignment': info['default_experience'],
        })
        # Add prefixed versions
        for prefix in PREFIX_MAP:
            prefixed_role = prefix + ' ' + base_role
            experience = PREFIX_MAP[prefix]
            rows.append({
                'job_role': prefixed_role,
                'skills': info['skills'],
                'domain': info['domain'],
                'required_skills': info['required_skills'],
                'demand_level_india': info['demand'],
                'experience_alignment': experience,
            })
    
    pd.DataFrame(rows).to_csv(OUTPUT_PATH, index=False, quoting=csv.QUOTE_MINIMAL)
    print(f'Wrote {len(rows)} rows to {OUTPUT_PATH}')

if __name__ == '__main__':
    main()
